// payment.proto — Razorpay gRPC payment service
syntax = "proto3";

package com.razorpay.payment;

option java_package = "com.razorpay.payment.grpc";
option java_outer_classname = "PaymentProto";
option java_multiple_files = true; // generates one .java file per message

// Request message:
message PaymentRequest {
  string merchant_id = 1;     // field 1: most common → 1-byte encoding
  int64 amount_paise = 2;     // amounts in paise (avoids float precision issues)
  string gateway = 3;         // HDFC, VISA, RUPAY, etc.
  PaymentType type = 4;
}

// Enum: proto3 first value MUST be 0 (default/unspecified)
enum PaymentType {
  PAYMENT_TYPE_UNSPECIFIED = 0;  // required zero value
  CREDIT_CARD = 1;
  DEBIT_CARD = 2;
  UPI = 3;
  NETBANKING = 4;
  WALLET = 5;
}

// Status request (minimal: just the ID):
message PaymentStatusRequest {
  string payment_id = 1;
}

// Response message:
message PaymentResponse {
  string payment_id = 1;
  PaymentStatus status = 2;
  string error_message = 3;   // empty string = no error (proto3 has no null)
  int64 processed_at_ms = 4;  // epoch milliseconds
}

enum PaymentStatus {
  PAYMENT_STATUS_UNSPECIFIED = 0;  // proto3: first enum = 0 = default
  INITIATED = 1;
  PROCESSING = 2;
  CAPTURED = 3;
  FAILED = 4;
  REFUNDED = 5;
}

// Service: defines available RPC methods
service PaymentService {
  rpc CreatePayment (PaymentRequest) returns (PaymentResponse);
  rpc GetPaymentStatus (PaymentStatusRequest) returns (PaymentResponse);
}

