// account.proto — backward compatibility demonstration

// VERSION 1 (initial schema):
// message AccountRequest {
//   string account_id = 1;
//   string legacy_pin = 2;   // will be removed in v2
//   string customer_name = 3;
// }

// VERSION 2 (removed legacy_pin — WRONG way: just delete field 2)
// WRONG:
// message AccountRequest {
//   string account_id = 1;
//   // field 2 deleted (DANGER: old clients still send field 2 data!)
//   string customer_name = 3;
//   string otp_method = 2;  // REUSED field 2 — BREAKING CHANGE!
// }

// VERSION 2 (CORRECT way: reserve the removed field)
syntax = "proto3";
package com.hdfc.account;

message AccountRequest {
  string account_id = 1;

  // Field 2 was 'legacy_pin' — REMOVED but reserved:
  reserved 2;
  reserved "legacy_pin";  // prevents name and number reuse

  string customer_name = 3;
  string otp_method = 4;  // NEW field gets NEW number (4, not 2)
}

// WHY RESERVED MATTERS:
// Old client sends: {account_id: 'ACC-1', legacy_pin: '1234', customer_name: 'Raj'}
// New server: ignores reserved field 2 (proto3: unknown fields dropped)
// Data integrity: preserved! (if 2 was reused for otp_method, 'legacy_pin' value
//   would be misread as 'otp_method' → security vulnerability!)

// VALID field number ranges:
// 1 - 15: 1 byte tag (for frequent fields)
// 16 - 2047: 2 bytes tag
// 19000 - 19999: RESERVED by Google (don't use)
// Max: 2^29 - 1 = 536,870,911

public class ProtoFieldRulesDoc { public static void main(String[] a) {
    System.out.println("Proto reserved: field 2 removed → reserved 2; prevents reuse");
} }

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Simulated generated classes (in real project: from protobuf-maven-plugin)
// PaymentRequest.java would be generated from payment.proto
// Here we simulate the API surface:

class SimulatedPaymentRequest {
    private final String merchantId;
    private final long amountPaise;
    private final String gateway;
    private final String type;

    private SimulatedPaymentRequest(Builder b) {
        this.merchantId = b.merchantId;
        this.amountPaise = b.amountPaise;
        this.gateway = b.gateway;
        this.type = b.type;
    }

    // Generated: builder pattern (immutable)
    static Builder newBuilder() { return new Builder(); }

    String getMerchantId() { return merchantId; }
    long getAmountPaise() { return amountPaise; }
    String getGateway() { return gateway; }
    String getType() { return type; }

    // Simulated serialization (real proto: toByteArray())
    byte[] toByteArray() {
        return (merchantId + "|" + amountPaise + "|" + gateway + "|" + type).getBytes();
    }

    // Simulated deserialization (real proto: parseFrom(bytes))
    static SimulatedPaymentRequest parseFrom(byte[] bytes) {
        String[] parts = new String(bytes).split("\\|");
        return newBuilder()
            .setMerchantId(parts[0]).setAmountPaise(Long.parseLong(parts[1]))
            .setGateway(parts[2]).setType(parts[3]).build();
    }

    static class Builder {
        String merchantId, gateway, type;
        long amountPaise;
        Builder setMerchantId(String v) { merchantId=v; return this; }
        Builder setAmountPaise(long v) { amountPaise=v; return this; }
        Builder setGateway(String v) { gateway=v; return this; }
        Builder setType(String v) { type=v; return this; }
        SimulatedPaymentRequest build() { return new SimulatedPaymentRequest(this); }
    }
}

@SpringBootTest
class ProtobufBuilderTest {
    @Test
    void buildPaymentRequest_allFieldsSet() {
        // Generated protobuf class: builder pattern
        SimulatedPaymentRequest request = SimulatedPaymentRequest.newBuilder()
            .setMerchantId("MRC-001")
            .setAmountPaise(50000L)     // ₹500.00
            .setGateway("HDFC")
            .setType("UPI")
            .build();

        assertEquals("MRC-001", request.getMerchantId());
        assertEquals(50000L, request.getAmountPaise());
        assertEquals("HDFC", request.getGateway());
    }

    @Test
    void serialization_roundTrip() throws Exception {
        SimulatedPaymentRequest original = SimulatedPaymentRequest.newBuilder()
            .setMerchantId("MRC-001").setAmountPaise(50000L)
            .setGateway("VISA").setType("CREDIT_CARD").build();

        // Serialize to bytes (binary in real proto):
        byte[] bytes = original.toByteArray();
        assertTrue(bytes.length > 0);

        // Deserialize back:
        SimulatedPaymentRequest restored = SimulatedPaymentRequest.parseFrom(bytes);
        assertEquals(original.getMerchantId(), restored.getMerchantId());
        assertEquals(original.getAmountPaise(), restored.getAmountPaise());
    }
}

// trade.proto — Zerodha order management service
syntax = "proto3";

package com.zerodha.trade;
option java_package = "com.zerodha.trade.grpc";
option java_multiple_files = true;

// Order type enum:
enum OrderType {
  ORDER_TYPE_UNSPECIFIED = 0;
  BUY = 1;
  SELL = 2;
  LIMIT_BUY = 3;
  LIMIT_SELL = 4;
  STOP_LOSS = 5;
}

// Order status enum:
enum OrderStatus {
  ORDER_STATUS_UNSPECIFIED = 0;
  PLACED = 1;
  PROCESSING = 2;
  FILLED = 3;
  REJECTED = 4;
  CANCELLED = 5;
}

// Request: what the client sends to place an order
message OrderRequest {
  string account_id = 1;
  string symbol = 2;         // NSE symbol: RELIANCE, TCS, etc.
  int32 quantity = 3;        // number of shares
  int64 price_paise = 4;     // limit price (0 for market orders)
  OrderType type = 5;
}

// Response: what the server sends back
message OrderResponse {
  string order_id = 1;
  OrderStatus status = 2;
  int64 fill_price_paise = 3; // actual fill price (0 if not filled)
  string rejection_reason = 4; // empty if successful
}

// Market data streaming request:
message MarketDataRequest {
  string symbol = 1;
  int64 from_timestamp_ms = 2; // epoch milliseconds
  int64 to_timestamp_ms = 3;
}

// Single price update (streamed):
message PriceUpdate {
  string symbol = 1;
  int64 price_paise = 2;
  int64 timestamp_ms = 3;
  int64 volume = 4;
}

// Service definition:
service TradeService {
  // Unary: one request → one response (like REST POST)
  rpc PlaceOrder (OrderRequest) returns (OrderResponse);

  // Server streaming: one request → STREAM of responses
  // 'stream' keyword = server sends multiple messages
  rpc GetMarketData (MarketDataRequest) returns (stream PriceUpdate);

  // Future additions:
  // rpc WatchLivePrice (WatchRequest) returns (stream PriceUpdate); // infinite stream
  // rpc BulkPlaceOrders (stream OrderRequest) returns (OrderResponse); // client streaming
}

// WHAT 'stream' MEANS:
// returns (OrderResponse): server sends exactly 1 message
// returns (stream PriceUpdate): server sends 0..N messages then closes the stream
// The client receives them one by one (like Iterator<PriceUpdate>)
// Great for: historical data, live feeds, large datasets

public class TradeProtoDoc { public static void main(String[] a) {
    System.out.println("Proto stream: returns (stream T) → server sends 0..N messages");
} }

import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// Simulated PaymentRequest for comparison
record PaymentRequestPojo(String merchantId, long amountPaise, String gateway, String type) {}

@Service
class ProtoVsJsonComparison {
    private final ObjectMapper mapper = new ObjectMapper();

    public int jsonSize(PaymentRequestPojo req) throws Exception {
        return mapper.writeValueAsString(req).getBytes().length;
    }

    // Simulated protobuf size (real proto would be smaller via varint encoding)
    // For this demo, we estimate based on protobuf encoding rules:
    public int estimatedProtoSize(PaymentRequestPojo req) {
        // Field 1 (merchant_id): tag(1B) + length(1B) + string bytes
        int field1 = 1 + 1 + req.merchantId().getBytes().length;
        // Field 2 (amount_paise): tag(1B) + varint (50000 fits in 2 bytes)
        int field2 = 1 + 2;
        // Field 3 (gateway): tag(1B) + length(1B) + string bytes
        int field3 = 1 + 1 + req.gateway().getBytes().length;
        // Field 4 (type): tag(1B) + varint enum value (1B)
        int field4 = 1 + 1;
        return field1 + field2 + field3 + field4;
    }

    public String analyzeCompression(PaymentRequestPojo req) throws Exception {
        int jsonBytes = jsonSize(req);
        int protoBytes = estimatedProtoSize(req);
        double ratio = (double) jsonBytes / protoBytes;
        long dailyRequests = 10_000_000;
        long jsonDailyMb = (jsonBytes * dailyRequests) / (1024 * 1024);
        long protoDailyMb = (protoBytes * dailyRequests) / (1024 * 1024);
        return String.format(
            "JSON: %d bytes, Proto: ~%d bytes (%.1fx smaller). Daily: JSON=%dMB, Proto=%dMB",
            jsonBytes, protoBytes, ratio, jsonDailyMb, protoDailyMb);
    }
}

@SpringBootTest
class ProtoSizeTest {
    @Autowired ProtoVsJsonComparison comparison;

    @Test
    void json_isLargerThanProto() throws Exception {
        PaymentRequestPojo req = new PaymentRequestPojo("MRC-001", 50000L, "HDFC", "UPI");
        int jsonSize = comparison.jsonSize(req);
        int protoSize = comparison.estimatedProtoSize(req);
        assertTrue(jsonSize > protoSize,
            "JSON (" + jsonSize + " bytes) should be larger than Proto (" + protoSize + " bytes)");
    }

    @Test
    void sizeComparison_logged() throws Exception {
        PaymentRequestPojo req = new PaymentRequestPojo("MRC-001", 50000L, "HDFC", "UPI");
        String analysis = comparison.analyzeCompression(req);
        System.out.println(analysis);
        assertTrue(analysis.contains("JSON") && analysis.contains("Proto"));
    }
}

