syntax = "proto3";

package com.razorpay.advanced;
import "google/protobuf/timestamp.proto";
import "google/protobuf/wrappers.proto";  // StringValue, Int64Value, etc.
import "google/protobuf/any.proto";

// Well-known types:
message TransactionRecord {
  string transaction_id = 1;
  int64 amount_paise = 2;

  // Timestamp: precise date/time (nanos resolution)
  // Better than int64 milliseconds: explicit semantic
  google.protobuf.Timestamp created_at = 3;
  google.protobuf.Timestamp settled_at = 4; // null = not settled yet (zero Timestamp)

  // StringValue wrapper: distinguishes null from empty string
  // Plain string: '' (empty) and missing both look like '' in proto3
  // StringValue: null = field not set; StringValue('') = explicitly empty string
  google.protobuf.StringValue failure_reason = 5; // null = success, 'timeout' = failure

  // Repeated: list of items
  repeated string tags = 6;

  // Map: key-value pairs
  map<string, string> metadata = 7;
}

// WHY StringValue vs string:
// string field: proto3 has no null. 'failure_reason' = '' could mean 'no failure' OR 'empty reason'
// google.protobuf.StringValue: hasValue() returns true/false → true null semantics
// Java: StringValue fieldVal = record.getFailureReason(); fieldVal.getValue() → 'timeout'
// If not set: record.hasFailureReason() returns false

// In Java (generated):
// Instant instant = Instant.ofEpochSecond(ts.getSeconds(), ts.getNanos());
// Timestamp ts = Timestamp.newBuilder()
//   .setSeconds(instant.getEpochSecond())
//   .setNanos(instant.getNano())
//   .build();

// Repeated field → List<String> in Java:
// record.getTagsList() → List<String>
// builder.addTags('fintech').addTags('india')

// Map field → Map<String, String> in Java:
// record.getMetadataMap() → Map<String, String>

public class WellKnownTypesDoc { public static void main(String[] a) {
    System.out.println("Well-known: Timestamp, StringValue (nullable), repeated (List), map (Map)");
} }

