// complete-payment.proto — full Razorpay payment service with all types
syntax = "proto3";

package com.razorpay.complete;
import "google/protobuf/timestamp.proto";
import "google/protobuf/wrappers.proto";

option java_package = "com.razorpay.complete.grpc";
option java_multiple_files = true;

enum PaymentGateway {
  GATEWAY_UNSPECIFIED = 0;
  HDFC = 1; VISA = 2; RUPAY = 3; AXIS = 4; ICICI = 5;
}

enum PaymentStatus {
  STATUS_UNSPECIFIED = 0;
  INITIATED = 1; PROCESSING = 2; CAPTURED = 3; FAILED = 4; REFUNDED = 5;
}

message PaymentRequest {
  string merchant_id = 1;           // → getMerchantId()
  int64 amount_paise = 2;           // → getAmountPaise() (long)
  PaymentGateway gateway = 3;       // → getGateway() (enum)
  repeated string tags = 4;         // → getTagsList() (List<String>)
  map<string, string> metadata = 5; // → getMetadataMap() (Map<String,String>)
  bool require_3ds = 6;             // → getRequire3Ds() (boolean)

  // Field 7 was 'promo_code' — REMOVED, reserved:
  reserved 7;
  reserved "promo_code";

  string idempotency_key = 8;       // for retry safety
}

message PaymentResponse {
  string payment_id = 1;
  PaymentStatus status = 2;
  google.protobuf.Timestamp created_at = 3;    // → Timestamp with seconds/nanos
  google.protobuf.StringValue failure_reason = 4; // → nullable (StringValue)
  int64 fill_amount_paise = 5;
}

message ListPaymentsRequest {
  string merchant_id = 1;
  int32 page_size = 2;
  string page_token = 3;
}

service PaymentService {
  rpc CreatePayment (PaymentRequest) returns (PaymentResponse);
  // Server streaming: one request → stream of payments
  rpc ListPayments (ListPaymentsRequest) returns (stream PaymentResponse);
}

// GENERATED JAVA API:
// PaymentRequest.newBuilder().setMerchantId('MRC-001')
//   .addTags('fintech').addTags('india')  → repeated field
//   .putMetadata('source', 'mobile')     → map field
//   .build()
// PaymentResponse.getCreatedAt()  → Timestamp
// Instant.ofEpochSecond(ts.getSeconds(), ts.getNanos())

public class CompleteProtoDoc { public static void main(String[] a) {
    System.out.println("Proto all types: scalar, enum, repeated (List), map (Map), Timestamp, StringValue (nullable)");
} }

// PROTO VERSIONING RULES FOR RAZORPAY

// ✅ SAFE CHANGES (backward compatible):
// 1. Add new fields (with new field numbers)
// 2. Remove fields (using 'reserved')
// 3. Change field name (number stays same → binary compatible)
// 4. Add new enum values (clients must handle unknown values gracefully)

// ❌ BREAKING CHANGES:
// 1. Change field number
// 2. Change field type (e.g., string to int32)
// 3. Remove fields WITHOUT 'reserved'
// 4. Change service method signatures

// Version 1 (initial):
// message PaymentRequestV1 {
//   string merchant_id = 1;
//   int64 amount_paise = 2;
//   string gateway = 3;
// }

// Version 2 (SAFE: adds currency field):
// message PaymentRequestV1 {  // same message, just add field
//   string merchant_id = 1;
//   int64 amount_paise = 2;
//   string gateway = 3;
//   string currency = 4;  // NEW: old clients don't send it → defaults to ''
// }                         // new clients send it → old servers ignore it

// Version 3 (MIGRATION: gateway replaced by gatewayConfig):
// message GatewayConfig {
//   string name = 1;      // HDFC, VISA, etc.
//   map<string,string> params = 2;  // gateway-specific params
// }
// message PaymentRequestV1 {
//   string merchant_id = 1;
//   int64 amount_paise = 2;
//   reserved 3; reserved 'gateway'; // SAFE removal
//   string currency = 4;
//   GatewayConfig gateway_config = 5;  // REPLACES gateway
// }

// VERSIONING STRATEGY OPTIONS:
// Option A: Evolve in place (recommended for internal services)
//   - Use reserved for removed fields
//   - Add fields with new numbers
//   - Same proto file, semantically versioned
// Option B: New package per major version
//   - package com.razorpay.payment.v1; → com.razorpay.payment.v2;
//   - Run old and new servers in parallel during migration
//   - Complete migration before deprecating v1

public class VersioningDoc { public static void main(String[] a) {
    System.out.println("Safe: add fields, reserved removed. Breaking: change type, reuse numbers.");
} }

