            .setGateway("VISA").setType("CREDIT_CARD").build();
        byte[] bytes = original.toBytes();
        var restored = SynthPaymentRequest.from(bytes);
        assertEquals(original.merchantId(), restored.merchantId());
        assertEquals(original.amountPaise(), restored.amountPaise());
    }
    @Test void v2_addsCurrency_backwardCompatible() {
        // Old client: sends without currency (uses default '')
        var v1Client = SynthPaymentRequest.newBuilder()
            .setMerchantId("MRC-OLD").setAmountPaise(1000L).setGateway("HDFC").build();
        assertEquals("", v1Client.currency()); // default: empty string (proto3 default)
        // New client: sends currency explicitly
        var v2Client = SynthPaymentRequest.newBuilder()
            .setMerchantId("MRC-NEW").setAmountPaise(1000L).setGateway("HDFC")
            .setCurrency("INR").build();
        assertEquals("INR", v2Client.currency());
    }
